  async updateItem(id: string, itemId: string, input: UpdateLicitacaoItemDto, authUser: AuthUserPayload) {
    const licitacao = await this.findOne(id, authUser);

    const item = await this.prisma.licitacaoItem.findFirst({
      where: {
        id: itemId,
        licitacaoId: licitacao.id,
      },
    });

    if (!item) {
      throw new NotFoundException('Item da licitacao nao encontrado');
    }

    if (input.descricao !== undefined && !input.descricao.trim()) {
      throw new BadRequestException('Informe a descricao do item.');
    }

    return this.prisma.$transaction(async (tx) => {
      const updated = await tx.licitacaoItem.update({
        where: { id: item.id },
        data: {
          numeroItem: this.normalizeOptionalText(input.numeroItem),
          numeroLote: this.normalizeOptionalText(input.numeroLote),
          descricao: input.descricao === undefined ? undefined : input.descricao.trim(),
          unidade: this.normalizeOptionalText(input.unidade),
          quantidade: this.parseOptionalDecimalInput(input.quantidade),
          valorReferencia: this.parseOptionalDecimalInput(input.valorReferencia),
          valorProposto: this.parseOptionalDecimalInput(input.valorProposto),
          marcaModelo: this.normalizeOptionalText(input.marcaModelo),
          observacoes: this.normalizeOptionalText(input.observacoes),
          status: input.status,
        },
      });

      await tx.activityLog.create({
        data: {
          organizationId: licitacao.organizationId,
          licitacaoId: licitacao.id,
          entityType: 'LICITACAO',
          entityId: licitacao.id,
          action: 'LICITACAO_ITEM_UPDATED',
          description: `Item ${updated.descricao} atualizado na licitacao`,
          metadata: {
            itemId: updated.id,
          },
        },
      });

      await this.createInternalNotifications(
        tx,
        licitacao.organizationId,
        authUser.sub,
        'Item atualizado',
        `${updated.descricao} foi atualizado em ${licitacao.titulo}.`,
        `/licitacoes/${licitacao.id}`,
      );

      return updated;
    });
  }

  async deleteItem(id: string, itemId: string, authUser: AuthUserPayload) {
    const licitacao = await this.findOne(id, authUser);

    const item = await this.prisma.licitacaoItem.findFirst({
      where: {
        id: itemId,
        licitacaoId: licitacao.id,
      },
    });

    if (!item) {
      throw new NotFoundException('Item da licitacao nao encontrado');
    }

    return this.prisma.$transaction(async (tx) => {
      await tx.licitacaoItem.delete({
        where: { id: item.id },
      });

      await tx.activityLog.create({
        data: {
          organizationId: licitacao.organizationId,
          licitacaoId: licitacao.id,
          entityType: 'LICITACAO',
          entityId: licitacao.id,
          action: 'LICITACAO_ITEM_DELETED',
          description: `Item ${item.descricao} removido da licitacao`,
          metadata: {
            itemId: item.id,
          },
        },
      });

      await this.createInternalNotifications(
        tx,
        licitacao.organizationId,
        authUser.sub,
        'Item removido',
        `${item.descricao} foi removido de ${licitacao.titulo}.`,
        `/licitacoes/${licitacao.id}`,
      );

      return { success: true };
    });
  }

  async createEmpenho(id: string, input: CreateLicitacaoEmpenhoDto, authUser: AuthUserPayload) {
    const licitacao = await this.findOne(id, authUser);

    if (!this.isLumeraOperator(authUser)) {
      throw new NotFoundException('Operacao indisponivel para este perfil');
    }

    const codigoEmpenho = input.codigoEmpenho.trim();
    if (!codigoEmpenho) {
      throw new BadRequestException('Informe o codigo do empenho.');
    }

    const valor = this.parseDecimalInput(input.valor);
    if (!valor) {
      throw new BadRequestException('Informe o valor do empenho.');
    }

    const nextSortOrder = await this.prisma.licitacaoEmpenho.count({
      where: { licitacaoId: licitacao.id },
    });

    return this.prisma.$transaction(async (tx) => {
      const empenho = await tx.licitacaoEmpenho.create({
        data: {
          licitacaoId: licitacao.id,
          codigoEmpenho,
          valor,
          dataEmpenho: input.dataEmpenho ? new Date(input.dataEmpenho) : null,
          dataPagamentoEmpenho: input.dataPagamentoEmpenho ? new Date(input.dataPagamentoEmpenho) : null,
          dataGeracaoBoleto: input.dataGeracaoBoleto ? new Date(input.dataGeracaoBoleto) : null,
          dataPagamentoBoleto: input.dataPagamentoBoleto ? new Date(input.dataPagamentoBoleto) : null,
          observacoes: this.normalizeOptionalText(input.observacoes),
          sortOrder: nextSortOrder,
        },
      });

      await tx.activityLog.create({
        data: {
          organizationId: licitacao.organizationId,
          licitacaoId: licitacao.id,
          entityType: 'LICITACAO',
          entityId: licitacao.id,
          action: 'LICITACAO_EMPENHO_CREATED',
          description: `Empenho ${codigoEmpenho} adicionado a licitacao`,
          metadata: {
            empenhoId: empenho.id,
          },
        },
      });

      await this.createInternalNotifications(
        tx,
        licitacao.organizationId,
        authUser.sub,
        'Novo empenho registrado',
        `Empenho ${codigoEmpenho} foi adicionado em ${licitacao.titulo}.`,
        `/licitacoes/${licitacao.id}`,
      );

      return empenho;
    });
  }

  async updateBasics(id: string, input: UpdateLicitacaoBasicsDto, authUser: AuthUserPayload) {
    const licitacao = await this.findOne(id, authUser);

    if (!this.isLumeraOperator(authUser)) {
      throw new NotFoundException('Operacao indisponivel para este perfil');
    }

    const titulo = input.titulo !== undefined ? input.titulo.trim() : undefined;
    if (input.titulo !== undefined && !titulo) {
      throw new BadRequestException('Informe o titulo da licitacao.');
    }

    return this.prisma.$transaction(async (tx) => {
      const updated = await tx.licitacao.update({
        where: { id: licitacao.id },
        data: {
          titulo,
          numeroProcesso: this.normalizeOptionalText(input.numeroProcesso),
          descricao: this.normalizeOptionalText(input.descricao),
          dataSessao: input.dataSessao ? new Date(input.dataSessao) : input.dataSessao === undefined ? undefined : null,
        },
        include: {
          organization: true,
          clientCompany: {
            include: {
              financialRule: true,
            },
          },
          etapa: true,
          responsaveis: { include: { user: true } },
        },
      });

      await tx.activityLog.create({
        data: {
          organizationId: licitacao.organizationId,
          licitacaoId: licitacao.id,
          entityType: 'LICITACAO',
          entityId: licitacao.id,
          action: 'LICITACAO_UPDATED',
          description: 'Dados basicos da licitacao atualizados',
        },
      });

      return updated;
    });
  }

